import{_ as r,C as E,o as t,c as o,a5 as n,b as g,w as a,a as s,E as l,a4 as u}from"./chunks/framework.sOZL8giL.js";const c=JSON.parse('{"title":"指挥官与工人","description":"","frontmatter":{},"headers":[],"relativePath":"04-多Agent架构/02-指挥官与工人.md","filePath":"04-多Agent架构/02-指挥官与工人.md","lastUpdated":null}'),p={name:"04-多Agent架构/02-指挥官与工人.md"};function i(d,e,b,B,h,S){const A=E("Mermaid");return t(),o("div",null,[e[1]||(e[1]=n('<h1 id="指挥官与工人" tabindex="-1">指挥官与工人 <a class="header-anchor" href="#指挥官与工人" aria-label="Permalink to &quot;指挥官与工人&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 4 模块的第 2 章。</p></blockquote><p>Anthropic 的多 Agent 架构实践——指挥官-工人架构、动态派生、八条提示词工程原则。</p><hr><h2 id="指挥官-工人架构" tabindex="-1">指挥官-工人架构 <a class="header-anchor" href="#指挥官-工人架构" aria-label="Permalink to &quot;指挥官-工人架构&quot;">​</a></h2><p>Anthropic 的多 Agent 研究系统采用经典的指挥官-工人（Lead Agent + Sub-Agents）架构。</p><p><strong>Lead Agent（指挥官）</strong>：接收用户查询，决定研究策略，将子任务分派给 Sub-Agents，汇总结果生成最终报告。它不直接做研究，而是做决策和协调。</p><p><strong>Sub-Agents（工人）</strong>：每个 Sub-Agent 在隔离的上下文中执行特定子任务——搜索、阅读文档、分析数据。完成后将结构化结果返回给 Lead Agent。</p><p>这种架构的核心优势是<strong>解耦</strong>：每个 Sub-Agent 有自己的上下文窗口，不会被其他 Agent 的信息干扰。Lead Agent 只需要理解汇总后的要点，不需要知道每个细节。</p>',9)),(t(),g(u,null,{default:a(()=>[l(A,{id:"mermaid-27",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E7%94%A8%E6%88%B7%E6%9F%A5%E8%AF%A2%5D%20--%3E%20B%5BLead%20Agent%20%E6%8C%87%E6%8C%A5%E5%AE%98%3Cbr%2F%3E%E6%8E%A5%E6%94%B6%E6%9F%A5%E8%AF%A2%20%E5%86%B3%E5%AE%9A%E7%AD%96%E7%95%A5%5D%0A%20%20%20%20B%20--%3E%20C%5B%E5%8A%A8%E6%80%81%E6%B4%BE%E7%94%9F%20Sub-Agent%201%3Cbr%2F%3E%E6%90%9C%E7%B4%A2%E4%BA%A7%E5%93%81%E5%92%8C%E6%94%B6%E5%85%A5%5D%0A%20%20%20%20B%20--%3E%20D%5B%E5%8A%A8%E6%80%81%E6%B4%BE%E7%94%9F%20Sub-Agent%202%3Cbr%2F%3E%E6%90%9C%E7%B4%A2%E7%AB%9E%E5%93%81%E6%9C%80%E6%96%B0%E8%BF%9B%E5%B1%95%5D%0A%20%20%20%20B%20--%3E%20E%5B%E5%8A%A8%E6%80%81%E6%B4%BE%E7%94%9F%20Sub-Agent%203%3Cbr%2F%3E%E6%90%9C%E7%B4%A2%E5%B8%82%E5%9C%BA%E5%AE%9A%E4%BD%8D%5D%0A%20%20%20%20C%20--%3E%7C%E7%BB%93%E6%9E%84%E5%8C%96%E7%BB%93%E6%9E%9C%7C%20F%5BLead%20Agent%20%E6%B1%87%E6%80%BB%5D%0A%20%20%20%20D%20--%3E%7C%E7%BB%93%E6%9E%84%E5%8C%96%E7%BB%93%E6%9E%9C%7C%20F%0A%20%20%20%20E%20--%3E%7C%E7%BB%93%E6%9E%84%E5%8C%96%E7%BB%93%E6%9E%9C%7C%20F%0A%20%20%20%20F%20--%3E%20G%5B%E7%94%9F%E6%88%90%E6%9C%80%E7%BB%88%E6%8A%A5%E5%91%8A%5D%0A%20%20%20%20C%20-.-x%20H%5BSub-Agent%20%E4%B9%8B%E9%97%B4%3Cbr%2F%3E%E4%B8%8D%E7%9B%B4%E6%8E%A5%E9%80%9A%E4%BF%A1%5D%0A%20%20%20%20D%20-.-x%20H%0A%20%20%20%20E%20-.-x%20H%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[s(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=n('<blockquote><p>💡 <strong>图解：</strong> 指挥官-工人的核心是&quot;单线汇报&quot;——工人之间永不通信，所有协调通过指挥官，避免状态同步的噩梦。</p></blockquote><hr><h2 id="动态派生" tabindex="-1">动态派生 <a class="header-anchor" href="#动态派生" aria-label="Permalink to &quot;动态派生&quot;">​</a></h2><p>Sub-Agents 不是预先静态配置的，而是根据任务需要动态派生。</p><p>用户说&quot;研究 OpenAI 的竞争格局&quot;，Lead Agent 可能会动态派生：</p><ul><li>一个 Sub-Agent 搜索 OpenAI 的产品和收入</li><li>一个 Sub-Agent 搜索 Google DeepMind 的最新进展</li><li>一个 Sub-Agent 搜索 Anthropic 的市场定位</li></ul><p>每个 Sub-Agent 收到不同的指令和搜索方向，各自在独立上下文中工作。这种动态派生确保了覆盖面——Lead Agent 不需要预知所有子任务，而是根据初步探索发现需要深入的方向后实时创建 Sub-Agent。</p><h3 id="关键约束" tabindex="-1">关键约束 <a class="header-anchor" href="#关键约束" aria-label="Permalink to &quot;关键约束&quot;">​</a></h3><p>Sub-Agents 之间不直接通信，所有协调通过 Lead Agent。这避免了多 Agent 之间的状态同步问题——每个 Sub-Agent 只和 Lead Agent 单线联系，汇报结果后就被销毁。</p><hr><h2 id="八条提示词工程原则" tabindex="-1">八条提示词工程原则 <a class="header-anchor" href="#八条提示词工程原则" aria-label="Permalink to &quot;八条提示词工程原则&quot;">​</a></h2><p>Anthropic 在构建多 Agent 研究系统时总结了八条核心原则：</p><p><strong>1. 明确角色定义</strong>：每个 Agent 的职责必须清晰无歧义。Lead Agent 负责决策和协调，Sub-Agent 负责执行和收集。角色混淆会导致重复工作或任务遗漏。</p><p><strong>2. 提供充分上下文</strong>：Sub-Agent 启动时需要足够的背景信息——任务目标、搜索策略、输出格式要求。上下文不足会导致 Sub-Agent 做无用功。</p><p><strong>3. 定义清晰的输出格式</strong>：Sub-Agent 返回的结果必须是结构化的——Lead Agent 需要解析和汇总多个来源的结果，格式不统一会导致汇总失败。</p><p><strong>4. 设置合理的超时和预算</strong>：每个 Sub-Agent 应有独立的 token 预算和时间限制。一个失控的 Sub-Agent 不应该拖垮整个系统。</p><p><strong>5. 实现优雅降级</strong>：如果某个 Sub-Agent 失败，Lead Agent 应该能感知到并调整策略，而不是静默忽略或整个任务失败。</p><p><strong>6. 验证 Sub-Agent 结果</strong>：Lead Agent 不应该盲目信任 Sub-Agent 的返回结果。需要进行基本的一致性检查——来源是否可靠、数据是否矛盾。</p><p><strong>7. 控制并发数量</strong>：并行 Sub-Agent 的数量应该受控。太多并行会增加成本、增加汇总复杂度、增加不一致风险。</p><p><strong>8. 记录决策过程</strong>：整个研究过程应该可追溯——Lead Agent 为什么派生了这些 Sub-Agent、每个 Sub-Agent 找到了什么、最终结论基于哪些证据。</p><hr><h2 id="实践中的权衡" tabindex="-1">实践中的权衡 <a class="header-anchor" href="#实践中的权衡" aria-label="Permalink to &quot;实践中的权衡&quot;">​</a></h2><p>指挥官-工人架构不是没有代价的。Lead Agent 的上下文窗口会累积所有 Sub-Agent 的返回结果，如果 Sub-Agent 很多或返回内容很长，Lead Agent 自己也可能面临上下文爆炸。</p><p>解决方案是让 Sub-Agent 的返回尽可能精简——只返回关键发现和来源链接，而不是完整的搜索结果。Lead Agent 可以在需要时再派新的 Sub-Agent 去深入某个方向。</p><p>另一个权衡是成本：每个 Sub-Agent 都是一次完整的 LLM 调用。对于简单任务，单 Agent 直接做可能更便宜。多 Agent 架构适合复杂度高、覆盖面要求广的任务。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>指挥官-工人架构：Lead Agent 决策协调，Sub-Agents 隔离执行</li><li>动态派生：根据任务需要实时创建 Sub-Agent，不预设静态配置</li><li>Sub-Agents 之间不直接通信，所有协调通过 Lead Agent</li><li>八条原则：角色定义、充分上下文、输出格式、预算控制、优雅降级、结果验证、并发控制、决策记录</li><li>权衡：Lead Agent 上下文累积、成本随 Sub-Agent 数量线性增长</li></ul><hr><p><strong>上一章</strong>: <a href="./01-何时用多Agent.html">何时用多Agent</a> | <strong>下一章</strong>: <a href="./03-六种Workflow模式.html">六种Workflow模式</a></p>',30))])}const C=r(p,[["render",i]]);export{c as __pageData,C as default};
